+
+.status-pill {
+  border: 1px solid #e2e8f0;
+  border-radius: 999px;
+  background: #f8fafc;
+  color: #64748b;
+  padding: 3px 8px;
+  font-size: 11px !important;
+  line-height: 14px !important;
+  font-weight: 760;
+}
+
+.status-pill.on {
+  border-color: #bbf7d0;
+  background: #f0fdf4;
+  color: #166534;
+}
+
+.gateway-switch {
+  width: 48px !important;
+  height: 28px !important;
+  border: 1px solid #cbd5e1 !important;
+  background: #cbd5e1 !important;
+}
+
+.gateway-switch[data-state="checked"] {
+  border-color: #111827 !important;
+  background: #111827 !important;
+}
+
+.gateway-switch > span {
+  width: 22px !important;
+  height: 22px !important;
+  transform: translateX(2px) !important;
+}
+
+.gateway-switch[data-state="checked"] > span {
+  transform: translateX(20px) !important;
+}
+
+.gateway-example-panel {
+  margin-top: 18px;
+  border: 1px solid #e2e8f0;
+  border-radius: 12px;
+  background: #ffffff;
+  padding: 14px;
+}
+
+.example-tabs {
+  display: flex;
+  gap: 4px;
+  border: 1px solid #e2e8f0;
+  border-radius: 10px;
+  background: #f8fafc;
+  padding: 4px;
+  overflow-x: auto;
+}
+
+.example-tab {
+  height: 30px !important;
+  min-width: 72px;
+  border-radius: 7px !important;
+  white-space: nowrap;
+}
+
+.example-copy {
+  margin-top: 14px;
+}
+
+.example-copy p {
+  margin-top: 6px;
+}
+
+.gateway-code {
+  margin-top: 14px !important;
+}
+
+.gateway-envelope {
+  margin-top: 10px !important;
+  color: #475569 !important;
+  font-size: 12px !important;
+  line-height: 17px !important;
+}
+
+.skill-install-panel {
+  border: 1px solid #e2e8f0;
+  border-radius: 12px;
+  background: #ffffff;
+  padding: 16px;
+}
+
+.skill-install-panel p {
+  margin-top: 6px;
+}
+
+.skill-install-row {
+  margin-top: 14px;
+  display: grid;
+  grid-template-columns: minmax(0, 1fr) auto;
+  gap: 10px;
+}
+
+.skill-list {
+  margin-top: 16px;
+  display: grid;
+  gap: 12px;
+}
+
+.skill-card {
+  border: 1px solid #e2e8f0;
+  border-radius: 12px;
+  display: grid;
+  grid-template-columns: minmax(0, 1fr) auto;
+  gap: 16px;
+  align-items: start;
+  background: #ffffff;
+  padding: 16px;
+}
+
+.skill-main {
+  min-width: 0;
+}
+
+.skill-title-row {
+  display: flex;
+  gap: 8px;
+  align-items: center;
+  flex-wrap: wrap;
+}
+
+.skill-card p {
+  margin-top: 7px;
+}
+
+.skill-meta {
+  margin-top: 8px;
+  color: #64748b;
+  font-size: 11px;
+  line-height: 16px;
+  overflow-wrap: anywhere;
+}
+
+.skill-actions {
+  display: flex;
+  gap: 8px;
+  align-items: center;
+  justify-content: flex-end;
+  flex-wrap: wrap;
+}
+
+.switch-label.disabled {
+  opacity: 0.62;
+}
+
+.setting-row {
+  margin-top: 18px;
+  display: grid;
+  grid-template-columns: 1fr auto;
+  gap: 16px;
+  align-items: center;
+  padding: 16px;
+}
+
+.compact-field {
+  width: 220px;
+}
+
+.setting-row strong {
+  display: block;
+  color: #0f172a;
+  font-size: 14px;
+}
+
+.setting-row span {
+  display: block;
+  margin-top: 3px;
+  color: #64748b;
+  font-size: 12px;
+}
+
+.code-block {
+  margin-top: 18px;
+  border: 1px solid #e2e8f0;
+  border-radius: 10px;
+  background: #0f172a;
+  color: #e2e8f0;
+  padding: 16px;
+  overflow: auto;
+  font-size: 13px;
+  line-height: 19px;
+}
+
+.data-table {
+  width: 100%;
+  margin-top: 18px;
+  border: 1px solid #e2e8f0;
+  border-collapse: separate;
+  border-spacing: 0;
+  border-radius: 12px;
+  overflow: hidden;
+  background: #ffffff;
+  font-size: 13px;
+}
+
+.data-table th,
+.data-table td {
+  border-bottom: 1px solid #eef2f7;
+  padding: 11px 12px;
+  text-align: left;
+  vertical-align: top;
+}
+
+.data-table th {
+  background: #f8fafc;
+  color: #475569;
+  font-size: 12px;
+  font-weight: 720;
+}
+
+.debug-list {
+  margin-top: 18px;
+  display: flex;
+  flex-direction: column;
+  gap: 10px;
+}
+
+.debug-item {
+  border: 1px solid #e2e8f0;
+  border-radius: 10px;
+  background: #ffffff;
+  padding: 12px;
+}
+
+.debug-item summary {
+  cursor: pointer;
+  color: #0f172a;
+  font-size: 13px;
+  font-weight: 650;
+}
+
+.debug-item pre {
+  overflow: auto;
+  color: #334155;
+  font-size: 12px;
+  line-height: 18px;
+}
+
+@media (max-width: 900px) {
+  .settings-shell {
+    grid-template-columns: 1fr;
+  }
+
+  .settings-sidebar {
+    min-height: auto;
+    position: static;
+  }
+
+  .settings-nav {
+    display: grid;
+    grid-template-columns: repeat(2, minmax(0, 1fr));
+  }
+
+  .settings-main {
+    padding: 22px;
+  }
+
+  .section-heading,
+  .provider-header,
+  .provider-grid,
+  .gateway-toggle-card,
+  .default-panel {
+    grid-template-columns: 1fr;
+  }
+
+  .gateway-switch {
+    justify-self: start;
+  }
+}
